import{_ as e,o as t,c as o,a}from"./app.76824a71.js";const b=JSON.parse('{"title":"Aki v. Sventhar, Oct 2019","description":"","frontmatter":{},"headers":[{"level":2,"title":"Case","slug":"case","link":"#case","children":[]},{"level":2,"title":"Proceedings","slug":"proceedings","link":"#proceedings","children":[]},{"level":2,"title":"Appeal","slug":"appeal","link":"#appeal","children":[]}],"relativePath":"government/court-cases-precedents/aki_v_sventhar_oct_2019.md","lastUpdated":1666539373000}'),n={name:"government/court-cases-precedents/aki_v_sventhar_oct_2019.md"},s=a('<h1 id="aki-v-sventhar-oct-2019" tabindex="-1">Aki v. Sventhar, Oct 2019 <a class="header-anchor" href="#aki-v-sventhar-oct-2019" aria-hidden="true">#</a></h1><h2 id="case" tabindex="-1">Case <a class="header-anchor" href="#case" aria-hidden="true">#</a></h2><p>With Oddish presiding, on 1st October 2019, Aki charged Sventhar with Harassment. Sventhar was found guilty of Harassment and was ordered to apologise to his victims. On appeal, Sventhar was additionally sentenced to a 6 week period of silence.</p><h2 id="proceedings" tabindex="-1">Proceedings <a class="header-anchor" href="#proceedings" aria-hidden="true">#</a></h2><p><strong>Aki</strong>:</p><blockquote><p>i would like to open up a lawsuit against Sventhar for harassment and intent to continue to harass</p></blockquote><p><strong>SpaceVolcano</strong>:</p><blockquote><p>The courts will hear the case of Aki vs Sventhar in the matter of harrassment. The matter of intent to continue will not be heard as proving intent to continue is impossible to prove since we can&#39;t read minds and predict future issues. Oddish will be presiding as judge.</p></blockquote><p><strong>Oddish</strong>:</p><blockquote><p>OK Court will now be in session.</p></blockquote><blockquote><p>Aki you have the floor for an opening statement.</p></blockquote><p><strong>Aki</strong>:</p><blockquote><p>Every Yoahtlan has the right to be free from harassment, and I believe that many of us, including myself, have not been free from harassment. There has been a targeted and continuous harassment campaign from Sventhar that has made most conversations devolve into ad hominim attacks and a source of stress for everyone in the nation. I don’t want to create a safe space where no one can drop hot takes or say spicy opinions. I also don’t want the dissolution of the freedom of speech. What I want is a line in the sand to be drawn that continuously and repetitively attacking a few individuals is going to go unpunished. Thank you.</p></blockquote><p><strong>Oddish</strong>:</p><blockquote><p>anything else to add?</p></blockquote><p><strong>Aki</strong>:</p><blockquote><p>Yes, I also would like to say that wanting a discord channel shut down or pushing a certain policy position is NOT a good reason to harass or target people</p></blockquote><p><strong>Oddish</strong>:</p><blockquote><p>okay</p></blockquote><blockquote><p>Sventhar I would like to call you to the stand to make your plea in regard to the prosecution</p></blockquote><p><strong>Sventhar</strong>:</p><blockquote><p>The defense pleads guilty to shit-posting, trolling, and baiting.</p></blockquote><p><strong>Aki</strong>:</p><blockquote><p>The charge of harassment?</p></blockquote><blockquote><p>Or are you including that in the trolling, baiting and shitposting</p></blockquote><p><strong>Sventhar</strong>:</p><blockquote><p>I plead not guilty to the charge of harassment.</p></blockquote><p><strong>Oddish</strong>:</p><blockquote><p>ok. to plead guilty to shitposting trolling and enacting in baitng but not guilty to harassment</p></blockquote><p><strong>Sventhar</strong>:</p><blockquote><p><a href="https://cdn.discordapp.com/attachments/348687557455904778/629007957975367690/unknown.png" target="_blank" rel="noreferrer">https://cdn.discordapp.com/attachments/348687557455904778/629007957975367690/unknown.png</a></p></blockquote><blockquote><p>Yes</p></blockquote><blockquote><p>The following is an example of a state law dealing with harassment:</p></blockquote><blockquote><p>&quot;S 240.25 Harassment in the first degree.</p></blockquote><blockquote><p>A person is guilty of harassment in the first degree when he or she intentionally and repeatedly harasses another person by following such person in or about a public place or places or by engaging in a course of conduct or by repeatedly committing acts which places such person in reasonable fear of physical injury. This section shall not apply to activities regulated by the national labor relations act, as amended, the railway labor act, as amended, or the federal employment labor management act, as amended.</p></blockquote><p><strong>Oddish</strong>:</p><blockquote><p>sven simmer down for a mo</p></blockquote><blockquote><p>Aki as the defendant is pleading not guilty to the charges of harassment, I call you now to present evidence of the defendant doing this</p></blockquote><blockquote><p>and testimonies</p></blockquote><p><strong>Aki</strong>:</p><blockquote><p>First, I would like to mention that I was followed from the discord into DM’s</p></blockquote><blockquote><p><a href="https://cdn.discordapp.com/attachments/348687557455904778/629008770797797376/image0.jpg" target="_blank" rel="noreferrer">https://cdn.discordapp.com/attachments/348687557455904778/629008770797797376/image0.jpg</a></p></blockquote><blockquote><p>During the whole “should pornographic images be banned”</p></blockquote><blockquote><p>Sven targeting orinnari</p></blockquote><blockquote><p><a href="https://cdn.discordapp.com/attachments/348687557455904778/629009096904802307/image0.jpg" target="_blank" rel="noreferrer">https://cdn.discordapp.com/attachments/348687557455904778/629009096904802307/image0.jpg</a></p></blockquote><p><strong>Oddish</strong>:</p><blockquote><p>do you have anything to support the transiton to dms from the discord</p></blockquote><p><strong>Aki</strong>:</p><blockquote><p>Yes I can let me get that after I post the other screenshots</p></blockquote><blockquote><p>Him targeting Orin again</p></blockquote><blockquote><p><a href="https://cdn.discordapp.com/attachments/348687557455904778/629009419560288257/image0.jpg" target="_blank" rel="noreferrer">https://cdn.discordapp.com/attachments/348687557455904778/629009419560288257/image0.jpg</a></p></blockquote><blockquote><p>Orin and myself this time</p></blockquote><blockquote><p><a href="https://cdn.discordapp.com/attachments/348687557455904778/629009790105944064/image0.jpg" target="_blank" rel="noreferrer">https://cdn.discordapp.com/attachments/348687557455904778/629009790105944064/image0.jpg</a></p></blockquote><blockquote><p>Sven accusing me of treason</p></blockquote><blockquote><p><a href="https://cdn.discordapp.com/attachments/348687557455904778/629009953524547584/image0.jpg" target="_blank" rel="noreferrer">https://cdn.discordapp.com/attachments/348687557455904778/629009953524547584/image0.jpg</a></p></blockquote><blockquote><p>Sventhar joyous over causing such a problem he got blocked</p></blockquote><blockquote><p><a href="https://cdn.discordapp.com/attachments/348687557455904778/629010197352022037/image0.jpg" target="_blank" rel="noreferrer">https://cdn.discordapp.com/attachments/348687557455904778/629010197352022037/image0.jpg</a></p></blockquote><blockquote><p>After an argument in politics irl</p></blockquote><blockquote><p><a href="https://cdn.discordapp.com/attachments/348687557455904778/629010280487190578/image0.jpg" target="_blank" rel="noreferrer">https://cdn.discordapp.com/attachments/348687557455904778/629010280487190578/image0.jpg</a></p></blockquote><blockquote><p><a href="https://cdn.discordapp.com/attachments/348687557455904778/629010366893916181/image0.jpg" target="_blank" rel="noreferrer">https://cdn.discordapp.com/attachments/348687557455904778/629010366893916181/image0.jpg</a></p></blockquote><blockquote><p>Me trying to express he should get help in good faith</p></blockquote><blockquote><p><a href="https://cdn.discordapp.com/attachments/348687557455904778/629010516290830371/image0.jpg" target="_blank" rel="noreferrer">https://cdn.discordapp.com/attachments/348687557455904778/629010516290830371/image0.jpg</a></p></blockquote><blockquote><p>And Bg saying we shouldn’t engage and sventhar sarcastic response</p></blockquote><blockquote><p><a href="https://cdn.discordapp.com/attachments/348687557455904778/629010634427727891/image0.jpg" target="_blank" rel="noreferrer">https://cdn.discordapp.com/attachments/348687557455904778/629010634427727891/image0.jpg</a></p></blockquote><blockquote><p>Him targeting Orin again and insulting him</p></blockquote><blockquote><p><a href="https://cdn.discordapp.com/attachments/348687557455904778/629010756255350797/image0.jpg" target="_blank" rel="noreferrer">https://cdn.discordapp.com/attachments/348687557455904778/629010756255350797/image0.jpg</a></p></blockquote><p><strong>Oddish</strong>:</p><blockquote><p>Aki do you ahve anything else to add to your case?</p></blockquote><p><strong>Aki</strong>:</p><blockquote><p>I wanted to post proof of the connection from DMs</p></blockquote><blockquote><p><a href="https://cdn.discordapp.com/attachments/348687557455904778/629012307757891614/image0.png" target="_blank" rel="noreferrer">https://cdn.discordapp.com/attachments/348687557455904778/629012307757891614/image0.png</a></p></blockquote><blockquote><p><a href="https://cdn.discordapp.com/attachments/348687557455904778/629012307757891615/image1.png" target="_blank" rel="noreferrer">https://cdn.discordapp.com/attachments/348687557455904778/629012307757891615/image1.png</a></p></blockquote><blockquote><p><a href="https://cdn.discordapp.com/attachments/348687557455904778/629012308487569429/image2.png" target="_blank" rel="noreferrer">https://cdn.discordapp.com/attachments/348687557455904778/629012308487569429/image2.png</a></p></blockquote><blockquote><p><a href="https://cdn.discordapp.com/attachments/348687557455904778/629012308487569430/image3.png" target="_blank" rel="noreferrer">https://cdn.discordapp.com/attachments/348687557455904778/629012308487569430/image3.png</a></p></blockquote><blockquote><p>As you can notice, I was frustrated over porn being posted and as you can see, not only was sventhar the primary troll in this instance but the dates are also the same time</p></blockquote><p><strong>Oddish</strong>:</p><blockquote><p>after reading through this evidence i can say that much of this isnt so much of harassment but more of indirect poking and memeing. the comments about orinari could be viewed as a basic observation given in a sarcastic manner or degrading. But nothing close to genuine repeated and personal attacks on a person.</p></blockquote><blockquote><p>I do have more to say but will withhold till im prepared to make a decision</p></blockquote><blockquote><p>TLDR: photos given arent strictly harassment, buy are demeaning in nature.</p></blockquote><p><strong>Aki</strong>:</p><blockquote><p>May I respond?</p></blockquote><p><strong>Oddish</strong>:</p><blockquote><p>Aki i will await your witness testimonies</p></blockquote><blockquote><p>out of curiosity. how many do you have</p></blockquote><p><strong>Aki</strong>:</p><blockquote><p>Depends on 2 peoples responses</p></blockquote><blockquote><p>8. 5 people said they would want to but fear retribution for speaking out. They will remain unnamed your honor</p></blockquote><p><strong>Oddish</strong>:</p><blockquote><p>also after speaking to the high [justice] about definitions harrassment in the charter is basically &quot;behavior purposefully and hurtfully directed at someone&quot;, especially if it causes them personal discomfort or causes them to consider leaving Yoahtl</p></blockquote><blockquote><p>as per the evidence given i can see comments that could be considered purposefully and hurtfully directed</p></blockquote><p><strong>Aki</strong>:</p><blockquote><p>Can it also be considered people have left yoahtl over purposeful and hurtful comments in the past</p></blockquote><p><strong>Oddish</strong>:</p><blockquote><p>i recall the orinari and tigen</p></blockquote><p><strong>Aki</strong>:</p><blockquote><p>Thank you your honor</p></blockquote><blockquote><p>I would like to enter additional evidence</p></blockquote><blockquote><p>this as a reply to me asking orin to be a witness</p></blockquote><blockquote><p><a href="https://cdn.discordapp.com/attachments/348687557455904778/629069284986978374/Screen_Shot_2019-10-02_at_5.34.46_PM.png" target="_blank" rel="noreferrer">https://cdn.discordapp.com/attachments/348687557455904778/629069284986978374/Screen_Shot_2019-10-02_at_5.34.46_PM.png</a></p></blockquote><blockquote><p>and sventhars response</p></blockquote><blockquote><p><a href="https://cdn.discordapp.com/attachments/348687557455904778/629069333066285087/Screen_Shot_2019-10-02_at_5.34.54_PM.png" target="_blank" rel="noreferrer">https://cdn.discordapp.com/attachments/348687557455904778/629069333066285087/Screen_Shot_2019-10-02_at_5.34.54_PM.png</a></p></blockquote><blockquote><p>Where he declared that his &quot;work is complete&quot; in draining orin and getting him to feel defeated</p></blockquote><p><strong>Oddish</strong>:</p><blockquote><p>ok to clarify some things. proving thins is alwasy difficult if theres room for error or need for clarification</p></blockquote><blockquote><p>after being told our clarification of harassment is different its changed some things</p></blockquote><blockquote><p>ill take evidence and have not said anything about not hearing things through</p></blockquote><blockquote><p>if i wasnt hearing shit through this case would be over much faster</p></blockquote><blockquote><p>but i want this solved as much as anyy of us do so well take the time to look at what is given</p></blockquote><blockquote><p>also on a more personal note. taking a moment to make a statement is not trading a day for being assblased. being in this chat all day to see the case through would be a btter representation of that</p></blockquote><p><strong>Aki</strong>:</p><blockquote><p>An additional piece of evidence</p></blockquote><blockquote><p><a href="https://cdn.discordapp.com/attachments/348687557455904778/629073290220142603/Screen_Shot_2019-10-02_at_5.51.55_PM.png" target="_blank" rel="noreferrer">https://cdn.discordapp.com/attachments/348687557455904778/629073290220142603/Screen_Shot_2019-10-02_at_5.51.55_PM.png</a></p></blockquote><p><strong>Oddish</strong>:</p><blockquote><p>Sventhar do you have any evidence to support your defence</p></blockquote><p><strong>Sventhar:</strong></p><blockquote><p>What exactly am I defending right now?</p></blockquote><blockquote><p>I thought this trial was about ‘drawing a line in the sand’</p></blockquote><p><strong>Oddish</strong>:</p><blockquote><p>the claims of harassment any evidence you deem worthy of this case present it</p></blockquote><p><strong>Sventhar</strong>:</p><blockquote><p>Also, is Aki prosecuting me on Orin’s behalf?</p></blockquote><blockquote><p>Like what am I defending?</p></blockquote><p><strong>Oddish</strong>:</p><blockquote><p>aki is the presecution</p></blockquote><blockquote><p>ori was evidence</p></blockquote><p><strong>Sventhar</strong>:</p><blockquote><p>Has Aki ever used the ‘Block’ feature on me? And if so, why did Aki ‘unblock’ me?</p></blockquote><blockquote><p>If Orin is upset about something, I think it would be better to have a separate trial for a separate incident.</p></blockquote><blockquote><p>Or are we just lumping all of the incidents of anytime I ever said something that hurt someone’s feelings?</p></blockquote><p><strong>Feathercrown</strong>:</p><blockquote><p>Objection Your Honor, the trial is about Sventhar&#39;s attempts at harrassment not at Aki&#39;s recieving them so blocking is irrelevant</p></blockquote><p><strong>Sventhar:</strong></p><blockquote><p>I would like a very clear example of something that I can defend.</p></blockquote><blockquote><p>I have already pleaded not guilty to harassment.</p></blockquote><p><strong>Oddish</strong>:</p><blockquote><p>yes but now you have to present evidnce that supports that claim</p></blockquote><p><strong>Sventhar:</strong></p><blockquote><p>At the beginning of the trial, I defined harassment.</p></blockquote><p><strong>Oddish</strong>:</p><blockquote><p>thats isnt how we define it</p></blockquote><p><strong>Sventhar:</strong></p><blockquote><p>Then could the court please define harassment for me?</p></blockquote><p><strong>Oddish</strong>:</p><blockquote><p>we are using our charter and our laws</p></blockquote><blockquote><p>harrassment in the charter is basically &quot;behavior purposefully and hurtfully directed at someone&quot;, especially if it causes them personal discomfort or causes them to consider leaving Yoahtl</p></blockquote><blockquote><p>i have alreay stated that</p></blockquote><p><strong>Sventhar:</strong></p><blockquote><p>If amendments to the charter have been made to adjust the definition of harassment and the citizens have not voted on this definition, then...</p></blockquote><blockquote><p>At the start of the trial was harassment clearly defined in the charter?</p></blockquote><p><strong>Oddish</strong>:</p><blockquote><p>that isnt how it works</p></blockquote><p><strong>Sventhar:</strong></p><blockquote><p>Your honor could I get a simple yes or no answer?</p></blockquote><blockquote><p>At the start of the trial was harassment clearly defined in the charter?</p></blockquote><p><strong>Oddish</strong>:</p><blockquote><p>please present your evidence that supports your plea of not guilty in reguards to the evidece the proscecutions evidence</p></blockquote><p><strong>Sventhar:</strong></p><blockquote><p>The defense rests.</p></blockquote><p><strong>Oddish</strong>:</p><blockquote><p>you have nothing to present?</p></blockquote><p><strong>Sventhar:</strong></p><blockquote><p>Please can I have a screenshot of where in the charter is the definition of harassment?</p></blockquote><p><strong>Oddish</strong>:</p><blockquote><p>id like to bring in freather to help clarify this</p></blockquote><blockquote><p>he has it</p></blockquote><blockquote><p>if you want the high justice then i can call him</p></blockquote><p><strong>Sventhar:</strong></p><blockquote><p><a href="https://cdn.discordapp.com/attachments/348687557455904778/629095207731724308/image0.png" target="_blank" rel="noreferrer">https://cdn.discordapp.com/attachments/348687557455904778/629095207731724308/image0.png</a></p></blockquote><blockquote><p>Harassment isn’t specifically defined and therefore reverts to the English language definition.</p></blockquote><blockquote><p>There was never intent to harass or harassment, I was memeing.</p></blockquote><blockquote><p>I never threatened anyone.</p></blockquote><blockquote><p>I never harmed anyone.</p></blockquote><blockquote><p>I never intimidated anyone with violence.</p></blockquote><p><strong>Oddish</strong>:</p><blockquote><p>you dont have to o be classed as harsassing</p></blockquote><p><strong>Sventhar:</strong></p><blockquote><p>There is no proof of any harassment other than hurt feelings.</p></blockquote><p><strong>Feathercrown</strong>:</p><blockquote><p>The charter and laws are often intentionally vague to prevent BS bypassing like what&#39;s happening here. The definition of harassment isn&#39;t defined specifically because people will try to do this and e-lawyer their way out of a harassment charge. If you really want a definition of harassment, where&#39;s the definition of literally any other non-invented word in the charter?</p></blockquote><blockquote><p>Regardless, if you really want evidence that harassment includes non-threats, the appeal for the court case WackyAki v. Meat312 with Councillor Klasikrok on [2nd December 2017] states that &quot;WackyAki, I believe that you have gone far enough in this matter. Any further harassment of meat on this issue will be considered actual harassment.&quot; This statement is in regards to Aki giving &quot;a long ass speech about how political corruption and bribery for votes corrupts the nation&quot;, was made by the highest legal judicial authority at the time (the Alcuahtl), and went uncontested. Sventhar, not only have you done this exact thing with Lukasmaps if I remember correctly, but this usage by the Alcuahtl Bgbba also means that the Yoahtlan definition of harassment is clearly not based on threats, so it&#39;s not identical to the IRL definition. The definition of harassment is basically &quot;behavior purposefully and hurtfully directed at someone&quot;, especially if it causes them personal discomfort or causes them to consider leaving Yoahtl. Not only has your behavior caused someone who I am under oath to keep anonymous to consider leaving Yoahtl as a whole, but in the cases provided as evidence it is clearly directed at Aki with the intent to cause them emotional distress. Additionally as Oddish stated this aligns with the IRL definition of harassment as it is degrading.</p></blockquote><blockquote><p>And no, &quot;memeing&quot; is not a valid defense. This is supported by the court precedent that &quot;Meming is not an excuse[...] if both parties aren&#39;t in on the meme&quot;</p></blockquote><p><strong>Sventhar:</strong></p><blockquote><p>This is a game, and if people didn&#39;t want to see what I had to say, all they had to do was it the block button on my name, Its not as though I was stalking and forcing my self on anybody. If people with disagreements to my opinion have hurt feeling, then they just have to block me since we are in game or on discord. Still no harm, still no threats. I exercised my freedom of speech and apparently people are lacking confidence to counter my memes. Secondly after this is done I will be sueing for impeachment of the High Justice for allowing this trial into the courts. Since this is a one sided trial and an opinionated decision on whether I was memeing or harassing since there is no hard evidence other than my word, and clearly the citizenry has a massive hate-boner for memes, opinions that disagree with theirs, and free speech. So Oddish you can go ahead and close this trial and rule based upon the mob rule of the current government and weak minded individuals.</p></blockquote><blockquote><p>This is all, you have my word that I was not harassing. I still plead not guilty.</p></blockquote><p><strong>Oddish</strong>:</p><blockquote><p>Aki your crossexamination of evidence begins</p></blockquote><p><strong>Aki:</strong></p><blockquote><p>First, do you recognize that even memes can upset or even harass people after anpoint</p></blockquote><p><strong>Sventhar:</strong></p><blockquote><p>No they’re memes, and they’re supposed to be funny.</p></blockquote><blockquote><p>Maybe my memes are too esoteric.</p></blockquote><p><strong>Aki:</strong></p><blockquote><p>Can you define esoteric</p></blockquote><p><strong>Feathercrown</strong>:</p><blockquote><p>Objection, memeing is not a valid defense under council precedent</p></blockquote><p><strong>Sventhar:</strong></p><blockquote><p>Esoteric - intended for or likely to be understood by only a small number of people with a specialized knowledge or interest.</p></blockquote><p><strong>Aki:</strong></p><blockquote><p>Do you also not post memes under the goal of a reaction?</p></blockquote><p><strong>Sventhar:</strong></p><blockquote><p>I post memes for the reaction of laughter. The goal of a meme is laughter and thought provoking.</p></blockquote><blockquote><p>Are we defining memes right now?</p></blockquote><blockquote><p>Do I actually have to define memes for you?</p></blockquote><p><strong>Aki:</strong></p><blockquote><p>I don’t seek to do so</p></blockquote><p><strong>Sventhar:</strong></p><blockquote><p>You wanted to ‘draw a line in the sand’</p></blockquote><blockquote><p>Are we any closer to that?</p></blockquote><p><strong>Oddish</strong>:</p><blockquote><p>yes</p></blockquote><p><strong>Aki:</strong></p><blockquote><p>You claimed that the ololtic had a hate boner for memes, are you saying that no other memes have been posted by the ololtic</p></blockquote><p><strong>Sventhar:</strong></p><blockquote><p>The ololtic posted self- loathing memes.</p></blockquote><blockquote><p>Therefore they hate memes and post them in a post-ironic way.</p></blockquote><blockquote><p>Basically we’re shitposting in the trial channel right now.</p></blockquote><p><strong>Aki:</strong></p><blockquote><p>Was this a meme?</p></blockquote><blockquote><p><a href="https://cdn.discordapp.com/attachments/348687557455904778/629103179572838400/image0.jpg" target="_blank" rel="noreferrer">https://cdn.discordapp.com/attachments/348687557455904778/629103179572838400/image0.jpg</a></p></blockquote><p><strong>Sventhar:</strong></p><blockquote><p>Literally it says ‘I’m always memeing’</p></blockquote><blockquote><p>This only supports my case</p></blockquote><blockquote><p>My existence is a meme</p></blockquote><blockquote><p>And even BG comes in here and tells me to ‘suck it’</p></blockquote><blockquote><p>That’s the definition of harassment.</p></blockquote><p><strong>Aki:</strong></p><blockquote><p>Is this “Esoteric”</p></blockquote><blockquote><p><a href="https://cdn.discordapp.com/attachments/348687557455904778/629103676115648512/image0.jpg" target="_blank" rel="noreferrer">https://cdn.discordapp.com/attachments/348687557455904778/629103676115648512/image0.jpg</a></p></blockquote><p><strong>Sventhar:</strong></p><blockquote><p>How many NPC memes has everyone else posted.</p></blockquote><blockquote><p>If harrasment is going to be defined as posting in discord, we should propse to spoiler everything anyone types and but trigger warnings on everyones name</p></blockquote><p><strong>Oddish</strong>:</p><blockquote><p>Sventhar your chance to cross examine evidence</p></blockquote><p><strong>Sventhar:</strong></p><blockquote><p>Aki, do you have the ability to read minds?</p></blockquote><p><strong>Aki:</strong></p><blockquote><p>I’m legally not allowed to answer that</p></blockquote><p><strong>Sventhar:</strong></p><blockquote><p>So you neither deny nor confirm that you have the ability to read minds. Therefore proving harassment vs. memery is impossible.</p></blockquote><blockquote><p>Did I ever physically threaten or harm you?</p></blockquote><blockquote><p>This question is for Aki.</p></blockquote><blockquote><p>Did I ever physically threaten or harm you or anyone else?</p></blockquote><p><strong>Aki:</strong></p><blockquote><p>Intent isn’t relevant to this case</p></blockquote><p><strong>Sventhar:</strong></p><blockquote><p>So if intent isn’t relevant, then the evidence that you’ve posted is irrelevant.</p></blockquote><p><strong>Aki:</strong></p><blockquote><p>The court recognized the evidence</p></blockquote><p><strong>Oddish</strong>:</p><blockquote><p>its entirely relevent</p></blockquote><p><strong>Sventhar:</strong></p><blockquote><p>How can you prove harassment without intent?</p></blockquote><p><strong>Oddish</strong>:</p><blockquote><p>its presents evidence to harassment reguardless of intent or meme. its the words given that have offended and hurt others.</p></blockquote><p><strong>Sventhar:</strong></p><blockquote><p>Did I ever physically threaten or harm you?</p></blockquote><p><strong>Aki:</strong></p><blockquote><p>The court doesn’t recognize intent as an argument</p></blockquote><blockquote><p>Also threats aren’t part of the definition</p></blockquote><p><strong>Sventhar:</strong></p><blockquote><p>So any action I do can be considered harassment?</p></blockquote><p><strong>Aki:</strong></p><blockquote><p>Sure, it might be wrong, but you can consider it</p></blockquote><p><strong>Sventhar:</strong></p><blockquote><p>So this whole trial is a meme?</p></blockquote><p><strong>Aki:</strong></p><blockquote><p>No</p></blockquote><blockquote><p>[...etc, continues along this same vein; masochists can read more here:</p></blockquote><blockquote><p><a href="https://discord.com/channels/278045721742147586/348687557455904778/628710244847190056" target="_blank" rel="noreferrer">https://discord.com/channels/278045721742147586/348687557455904778/628710244847190056</a>]</p></blockquote><p><strong>Oddish</strong>:</p><blockquote><p>as sventhar has pleaded guilty to meming, shitposting and baiting.</p></blockquote><blockquote><p>Given that baiting is intent to get a response and continue to harass people. and those actions have lead to people feeling uncomfortable the courts will find you guilty of harassment.</p></blockquote><blockquote><p>From this I will now be ruling a &#39;line in the sand&#39; continued &#39;memeing&#39; &#39;baiting&#39; and &#39;shitposting&#39; that cause updset to others and lead to them feeling uncomfortable or unhappy being in our community will lead to a warning placed upon the person or persons who are causing said harm. Reguardless of intent or its just a game bro actions taken can and will hurt others. Failure to understand this will result in said warning given. First warning will result in an apology to be made by the harassing party. Second warning will result in another apology and given the word that the next time this occurs they are to be removed from the discord as they clearly are only here to cause harm to others.</p></blockquote><blockquote><p>Additionally. Sventhar this will regard to your first warning. The courts would like to ask you to make an apology to Wakiaky, Orinari and others who have been hurt by your actions.</p></blockquote><h2 id="appeal" tabindex="-1">Appeal <a class="header-anchor" href="#appeal" aria-hidden="true">#</a></h2><p><strong>SpaceVolcano</strong>:</p><blockquote><p>The court will grant the appeal in the matter Aki vs Sventhar ruled upon by presiding judge Oddish.</p></blockquote><blockquote><p>As to make this trial expedient the court will be submitting the majority of statements. Simply for record and to uphold procedure.</p></blockquote><blockquote><p>The reiteration of the complaint as submitted by Sventhar</p></blockquote><blockquote><p><a href="https://cdn.discordapp.com/attachments/348687557455904778/629139701525381121/unknown.png" target="_blank" rel="noreferrer">https://cdn.discordapp.com/attachments/348687557455904778/629139701525381121/unknown.png</a></p></blockquote><blockquote><p>Additional evidence for the appeal as submitted by Grimm</p></blockquote><blockquote><p><a href="https://cdn.discordapp.com/attachments/348687557455904778/629139954731188224/unknown.png" target="_blank" rel="noreferrer">https://cdn.discordapp.com/attachments/348687557455904778/629139954731188224/unknown.png</a></p></blockquote><blockquote><p>Further Evidence as submitted by JustMatter</p></blockquote><blockquote><p><a href="https://cdn.discordapp.com/attachments/348687557455904778/629140305144315954/unknown.png" target="_blank" rel="noreferrer">https://cdn.discordapp.com/attachments/348687557455904778/629140305144315954/unknown.png</a></p></blockquote><blockquote><p>The court would like to call upon bgbba as an expert witness to make a statement on how the Nation has handled similar situations to the issue of harrassment in the past.</p></blockquote><p><strong>bgbba</strong>:</p><blockquote><p>I&#39;ll start off by stating that harassment has been kept deliberately vague as a way to accommodate the fact we can&#39;t prove intent. It&#39;s hard because the court can&#39;t pre-emptively attack the issue of harassment, so by the time that harassment actually causes somebody to leave Yoahtl or disengage from the community often it&#39;s too late.</p></blockquote><blockquote><p>So there&#39;s this historical precedent of the Alcuahtl, Chieftain, or whoever being able to say &#39;alright calm down this is far enough you&#39;re starting to hurt people&#39; and normally people just handle that and accept that they&#39;re starting to damage community relations and their relationships with others in this community.</p></blockquote><blockquote><p>The problem has always come in when people just straight up refuse to take the hint and see people telling them that they&#39;re damaging others as some sort of imposition on themselves. Re: WackyAki vs Meat312, which was in large part precipitated because WackyAki refused to take the hint and instead kept pressing on meat even when the government had made it clear we were going to stop the behavior he was going after meat for.</p></blockquote><blockquote><p>The fundamental question at stake here is what constitutes community in Yoahtl. Is our community simply a platform for people’s individual interests regardless of their impact on others? Or is it an organism unto itself, formed as a series of infinite compromises between all the individuals?</p></blockquote><blockquote><p>What makes Yoahtl unique is that unlike any other civ town we are explicitly a community rather than just an organization. The government of Yoahtl and all its institutions are simply extra, created as a means of better facilitating the formation of a functional community. Yoahtl, in short, is a family. A big messy one but a family nonetheless. This ‘collective of individuals’ mentality that pervades civ And has since day one is anathema to Yoahtl. At every juncture, we have determined that as soon as an individual stops treating us as a community and starts treating us as simply a platform for their individual interests we have the right to take away their ability to use us as a platform for their individual interests at the expense of everybody else, Sventhar has run up against this distinction</p></blockquote><blockquote><p>In short: Sventhar has a right to be in this community but not at the expense of others. His behavior badly damaged relations between the government and the people, and has continued the campaign of division and unneeded arguments in a manner similar to Isit or Fishywa or Qua or ZachAttack. Civ is littered with examples of former Yoahtlans who couldn’t realize the difference between a platform and a community and suffered the consequences. In summation, we absolutely have the right to start being harder on people for exploiting us and using Yoahtl as a platform. You don’t shit where you eat and if you want to live in a sewer we don’t need to turn a blind eye.</p></blockquote><blockquote><p>Testimony given, we are a community not a platform, if you can’t handle that then we don’t need to let you have full perms in Discord</p></blockquote><blockquote><p>Oh yeah as an addendum: Yoahtl is the only town, group, or nation in civ with a ‘closed’ discord policy that doesn’t have the same ingame. We have made it very clear from day one when Lieb and I made this discord that this discord was meant to facilitate the ingame community, not the other way around. This discord is a tool for us to do things in Minecraft, it’s why Zach got banned for shilling other games, it’s why people who lurk in every discord obsessively are banned on sight like Yellofishy and Seiftfizz, it’s why people who lurk and spy like TVman aren’t in here. This discord is one of the most secure and exclusive. Again, it’s a community facilitation tool not a platform. You have free speech ingame, if you need to lurk discord on your phone all day, go do it elsewhere because it’s not needed for community facilitation.</p></blockquote><p><strong>SpaceVolcano</strong>:</p><blockquote><p>Thank you Bgbba,</p></blockquote><blockquote><p>The court would like to call upon NeoTide as an expert witness to make a statement on Discord Moderation, and how moderation applies to harassment and irreverent and irrelevant discussion. You have 72hours to make your statement, please take as much time as you need of the 72 hours, the court proceeding will not continue until you close your statement.</p></blockquote><p><strong>NeoTide</strong>:</p><blockquote><p>The effects of rampant harassment, like in the case of Sventhar&#39;s, are as you all know quite damning. Problems have previously arisen with similar circumstances which proved to be a severe impediment and betrayal of what Yoahtl aspires to be.</p></blockquote><blockquote><p>In previous outbursts of Sventhar&#39;s, the Councilors&#39; abilities to halt conversation and &quot;censor&quot; the defendant undeniably saved the greater Yoahtl community from similar losses. No matter the circumstances of the defendant, his actions are disruptive and qualify for intervention from those with applicable perms.</p></blockquote><blockquote><p>The specific tools employed which are being advocated for continued use involve limiting the ability to:</p></blockquote><blockquote><p>- send messages - upload images - preview linked images - react to posts</p></blockquote><p><strong>SpaceVolcano</strong>:</p><blockquote><p>The court would like to call Feathercrown as an expert witness on the Goverment&#39;s excutive powers and how it particularly applies managing citizens and handling people who cause disruptions. You have 72 hours to make your statment, and the court proceeding will not continue until you close your statement.</p></blockquote><p><strong>Feathercrown</strong>:</p><blockquote><p>The Yoahtlan government has always had the authority to do pretty much whatever it has to in the Discord. This Discord was created as a place for people to contribute usefully to ingame projects, not as a place for metagame shittery. As such, any significant, repeated disruptions will not be tolerated. Anything that goes beyond a sinple disruption-- eg. harassment-- can and will be met with a kick/ban from the server, as has been done many times before. This Discord is a curated space, not a free-for-all.</p></blockquote><blockquote><p>As for how it relates to executive powers, it&#39;s the government&#39;s job to enforce the laws, and the laws say no harassment. In case it was unclear, the laws do not say freedom to post anything, in the Discord or otherwise. As in real life, freedom of speech does not extend to every possible form of speech, and it&#39;s the government&#39;s job to enforce the areas where it does not apply.</p></blockquote><p><strong>SpaceVolcano</strong>:</p><blockquote><p>Thank you feather,</p></blockquote><blockquote><p>The courts would now like to call on LukasMaps to make to a statement on freedom of expression, freedom of speech, and freedom from harrasment and how the goverment has handled these issues.</p></blockquote><p><strong>LukasMaps</strong>:</p><blockquote><p>I abstain from making a statement as the only sentiment I wish to express at this time is that I believe this trial should be settled in an expedient manner so as to settle the question of what counts as harassment, seeing as though the issue has again surfaced in the context of the electoral process.</p></blockquote><p><strong>SpaceVolcano</strong>:</p><blockquote><p>Thank you Lukas</p></blockquote><blockquote><p>The court would like to call on Oddish to make a statement about his ruling and why</p></blockquote><blockquote><p>He felt it was appealed</p></blockquote><blockquote><p>How the courts may possibly have the best outcome in future trials by using the current laws and precedents we have in place.</p></blockquote><p><strong>Oddish</strong>:</p><blockquote><p>The ruling that was made used both the guilty plea and non guilty plea in its finalisation. Taking the admission to certain acts and finding the defence lacking, my decision came to guilty of all charges. There was also a logical link between &#39;baiting&#39; and the defences focus of asking where intent was. By acknowledging that &#39;baiting&#39; is intent to gain a reaction and then target players in certain ways that make them uncomfortable its easy enough to see that&#39; baiting&#39; shows intent to harass. As the plea for &#39;baiting&#39; and &#39;trolling&#39; was guilty, the defendant was found guilty of harassment as well.</p></blockquote><blockquote><p>This may have not been made clear enough in my precedent and comments, but the idea was to find a way that the plaintiffs request of &#39;drawing a line in the sand&#39; could be achieved while still allowing people to express themselves. This is how I came up with the warning system. As for the fact it was appealed when the actual defendant &#39;sventhar&#39; wanted the case over and done with, I dont know. But it will give us an opportunity to set things not in sand but stone and from this be able to help keep people safe and comfortable in our community. So I am in a way glad this has happened.</p></blockquote><blockquote><p>As for how the courts can achieve the best outcome I believe having some rough definition of harassment where it states more of the discomfort it can cause and not how to do it, it will allow people to remain confident in the courts. Yes by not listing things that count as harassment people will complain about not knowing, thats why we give warnings, that&#39;s why we have the vague ideas. If a person is upset with you contacting them in a certain way or with certain words or whatever they should have a way to be able to sue and try to protect themselves.</p></blockquote><blockquote><p>Forcing definitions will only lead to people finding new ways to go round the law, or to layer their way to riches by suing everyone. Left open to interpretation it allows the courts to look at a case and its evidence and judge with more flexibility to help protect the people. Setting precedents specific to things will only take more time when something new arises. Having them vague helps save time for all parties.</p></blockquote><p><strong>SpaceVolcano</strong>:</p><blockquote><p>Thank you Oddish. The courts now have collected all the evidence required.</p></blockquote><blockquote><p>The appellate ruling:</p></blockquote><blockquote><p><a href="https://docs.google.com/document/d/1e_0kW2gW5NVHTLcWNlXimGa0arDqOU2d7bH2yAuAot8" target="_blank" rel="noreferrer">https://docs.google.com/document/d/1e_0kW2gW5NVHTLcWNlXimGa0arDqOU2d7bH2yAuAot8</a></p></blockquote><blockquote><p>TL:DR Don&#39;t be a dick guys. Be reasonable, be courteous, be respectful. Our discord is a privilege. Keep it fun, and memes are more fun if everyone is in on them. Trial channel is reopened.</p></blockquote>',327),i=[s];function r(l,p,c,h,u,d){return t(),o("div",null,i)}const m=e(n,[["render",r]]);export{b as __pageData,m as default};
